7	#include <rime/candidate.h>
8	#include <rime/common.h>
9	#include <rime/composition.h>
10	#include <rime/config.h>
11	#include <rime/context.h>
12	#include <rime/key_event.h>
13	#include <rime/menu.h>
14	#include <rime/processor.h>
15	#include <rime/schema.h>
16	#include <rime/switcher.h>
17	#include <rime/ticket.h>
18	#include <rime/translation.h>
19	#include <rime/translator.h>
20	
21	namespace rime {
22	
23	Switcher::Switcher(const Ticket& ticket) : Processor(ticket) {
24	  context_->set_option("dumb", true);  // not going to commit anything
25	
26	  // receive context notifications
27	  context_->select_notifier().connect([this](Context* ctx) { OnSelect(ctx); });
28	
29	  user_config_.reset(Config::Require("user_config")->Create("user"));
30	  InitializeComponents();
31	  LoadSettings();
32	}
33	
34	Switcher::~Switcher() {
35	  if (active_) {
36	    Deactivate();
37	  }
38	}
39	
40	void Switcher::RestoreSavedOptions() {
41	  if (user_config_) {
42	    for (const string& option_name : save_options_) {
43	      bool value = false;
44	      if (user_config_->GetBool("var/option/" + option_name, &value)) {
45	        engine_->context()->set_option(option_name, value);
46	      }
47	    }
48	  }
49	}
50	
51	ProcessResult Switcher::ProcessKeyEvent(const KeyEvent& key_event) {
52	  for (const KeyEvent& hotkey : hotkeys_) {
53	    if (key_event == hotkey) {
54	      if (!active_ && engine_) {
55	        Activate();
56	      } else if (active_) {
57	        HighlightNextSchema();
58	      }
59	      return kAccepted;
60	    }
61	  }
62	  if (active_) {
63	    for (auto& p : processors_) {
64	      ProcessResult result = p->ProcessKeyEvent(key_event);
65	      if (result != kNoop) {
66	        return result;
67	      }
68	    }
69	    if (key_event.release() || key_event.ctrl() || key_event.alt()) {
70	      return kAccepted;
71	    }
72	    int ch = key_event.keycode();
73	    if (ch == XK_space || ch == XK_Return) {
74	      context_->ConfirmCurrentSelection();
75	    } else if (ch == XK_Escape) {
76	      Deactivate();
77	    }
78	    return kAccepted;
79	  }
80	  return kNoop;
81	}
82	
83	void Switcher::HighlightNextSchema() {
84	  Composition& comp = context_->composition();
85	  if (comp.empty() || !comp.back().menu)
86	    return;
87	  Segment& seg(comp.back());
88	  int index = seg.selected_index;
89	  an<Candidate> option;
90	  do {
91	    ++index;  // next
92	    int candidate_count = seg.menu->Prepare(index + 1);
93	    if (candidate_count <= index) {
94	      index = 0;  // passed the end; rewind
95	      break;
96	    } else {
97	      option = seg.GetCandidateAt(index);
98	    }
99	  } while (!option || option->type() != "schema");
100	  seg.selected_index = index;
101	  seg.tags.insert("paging");
102	  return;
103	}
104	
105	/*
106	  Example configuration:
107	
108	  ```yaml
109	  schema_list:
110	  - case: [mode/wubi, mode/wubi_pinyin]
111	    schema: wubi_pinyin
112	  - case: [mode/wubi]
113	    schema: wubi86
114	  - case: [mode/default]
115	    schema: pinyin
116	
117	  mode:
118	    wubi: false
119	    wubi_pinyin: false
120	    default: true
121	  ```
122	*/
123	
124	static an<ConfigValue> ParseSchemaListEntry(Config* config,
125	                                            an<ConfigMap> entry_map) {
126	  if (!entry_map)
127	    return nullptr;
128	  auto schema_property = entry_map->GetValue("schema");
129	  if (!schema_property)
130	    return nullptr;
131	  if (auto case_conditions = As<ConfigList>(entry_map->Get("case"))) {
132	    for (auto iter = case_conditions->begin(); iter != case_conditions->end();
133	         ++iter) {
134	      if (auto condition_variable = As<ConfigValue>(*iter)) {
135	        bool condition_met = false;
136	        if (!config->GetBool(condition_variable->str(), &condition_met) ||
137	            !condition_met) {
138	          return nullptr;
139	        }
140	      }
141	    }
142	  }
143	  return schema_property;
144	}
145	
146	int Switcher::ForEachSchemaListEntry(
147	    Config* config,
148	    function<bool(const string& schema_id)> process_entry) {
149	  auto schema_list = config->GetList("schema_list");
150	  if (!schema_list)
151	    return 0;
152	  int num_processed_entries = 0;
153	  for (auto iter = schema_list->begin(); iter != schema_list->end(); ++iter) {
154	    auto entry = ParseSchemaListEntry(config, As<ConfigMap>(*iter));
155	    if (!entry)
156	      continue;
157	    const string& schema_id = entry->str();
158	    ++num_processed_entries;
159	    if (!process_entry(schema_id))
160	      break;
161	  }
162	  return num_processed_entries;
163	}
164	
165	void Switcher::SetActiveSchema(const string& schema_id) {
166	  if (user_config_) {
167	    user_config_->SetString("var/previously_selected_schema", schema_id);
168	    user_config_->SetInt("var/schema_access_time/" + schema_id, time(NULL));
169	    // persist recently used schema and options that have changed
170	    user_config_->Save();
171	  }
172	}
173	
174	Schema* Switcher::CreateSchema() {
175	  Config* config = schema_->config();
176	  if (!config)
177	    return nullptr;
178	  string previous;
179	  if (user_config_ && !fix_schema_list_order_) {
180	    user_config_->GetString("var/previously_selected_schema", &previous);
181	  }
182	  string recent;
183	  ForEachSchemaListEntry(config, [&previous, &recent](const string& schema_id) {
184	    if (previous.empty() || previous == schema_id) {
185	      recent = schema_id;
186	      return /* continue = */ false;
187	    }
188	    if (recent.empty())
189	      recent = schema_id;
190	    return /* continue = */ true;
191	  });
192	  if (recent.empty())
193	    return nullptr;
194	  else
195	    return new Schema(recent);
196	}
197	
198	void Switcher::SelectNextSchema() {
199	  if (translators_.empty())
200	    return;
201	  auto xlator = translators_[0];  // schema_list_translator
202	  if (!xlator)
203	    return;
204	  Menu menu;
205	  menu.AddTranslation(xlator->Query("", Segment()));
206	  if (menu.Prepare(2) < 2)
207	    return;
208	  auto command = As<SwitcherCommand>(menu.GetCandidateAt(1));
209	  if (!command)
210	    return;
211	  command->Apply(this);
212	}
213	
214	bool Switcher::IsAutoSave(const string& option) const {
215	  return save_options_.find(option) != save_options_.end();
216	}
217	
218	void Switcher::OnSelect(Context* ctx) {
219	  LOG(INFO) << "a switcher option is selected.";
220	  if (auto command = As<SwitcherCommand>(ctx->GetSelectedCandidate())) {
221	    command->Apply(this);
222	  }
223	}
224	
225	void Switcher::RefreshMenu() {
226	  Composition& comp = context_->composition();
227	  if (comp.empty()) {
228	    // no longer need this to make context_->IsComposing() == true
229	    // context_->set_input(" ");
230	    Segment seg(0, 0);  // empty range
231	    seg.prompt = caption_;
232	    comp.AddSegment(seg);
233	  }
234	  auto menu = New<Menu>();
235	  comp.back().menu = menu;
236	  for (auto& translator : translators_) {
237	    if (auto t = translator->Query("", comp.back())) {
238	      menu->AddTranslation(t);
239	    }
240	  }
241	}
242	
243	void Switcher::Activate() {
244	  LOG(INFO) << "switcher is activated.";
245	  context_->set_option("_fold_options", fold_options_);
246	  RefreshMenu();
247	  engine_->set_active_engine(this);
248	  active_ = true;
249	}
250	
251	void Switcher::Deactivate() {
252	  active_ = false;
253	  engine_->set_active_engine();
254	  context_->Clear();
255	}
256	
257	void Switcher::DeactivateAndApply(function<void()> apply) {
258	  active_ = false;
259	  engine_->set_active_engine();
260	  apply();
261	  context_->Clear();
262	}
263	
264	void Switcher::LoadSettings() {
265	  Config* config = schema_->config();
266	  if (!config)
267	    return;
268	  if (!config->GetString("switcher/caption", &caption_) || caption_.empty()) {
269	    caption_ = ":-)";
270	  }
271	  if (auto hotkeys = config->GetList("switcher/hotkeys")) {
272	    hotkeys_.clear();
273	    for (size_t i = 0; i < hotkeys->size(); ++i) {
274	      auto value = hotkeys->GetValueAt(i);
275	      if (!value)
276	        continue;
277	      hotkeys_.push_back(KeyEvent(value->str()));
278	    }
279	  }
280	  if (auto options = config->GetList("switcher/save_options")) {
281	    save_options_.clear();
282	    for (auto it = options->begin(); it != options->end(); ++it) {
283	      auto option_name = As<ConfigValue>(*it);
284	      if (!option_name)
285	        continue;
286	      save_options_.insert(option_name->str());
287	    }
288	  }
289	  config->GetBool("switcher/fold_options", &fold_options_);
290	  config->GetBool("switcher/fix_schema_list_order", &fix_schema_list_order_);
291	}
292	
293	void Switcher::InitializeComponents() {
294	  processors_.clear();
295	  translators_.clear();
296	  if (auto c = Processor::Require("key_binder")) {
297	    an<Processor> p(c->Create(Ticket(this)));
298	    processors_.push_back(p);
299	  } else {
300	    LOG(WARNING) << "key_binder not available.";
301	  }
302	  if (auto c = Processor::Require("selector")) {
303	    an<Processor> p(c->Create(Ticket(this)));
304	    processors_.push_back(p);
305	  } else {
306	    LOG(WARNING) << "selector not available.";
307	  }
308	  DLOG(INFO) << "num processors: " << processors_.size();
309	  if (auto c = Translator::Require("schema_list_translator")) {
310	    an<Translator> t(c->Create(Ticket(this)));
311	    translators_.push_back(t);
312	  } else {
313	    LOG(WARNING) << "schema_list_translator not available.";
314	  }
315	  if (auto c = Translator::Require("switch_translator")) {
316	    an<Translator> t(c->Create(Ticket(this)));
317	    translators_.push_back(t);
318	  } else {
319	    LOG(WARNING) << "switch_translator not available.";
320	  }
321	  DLOG(INFO) << "num translators: " << translators_.size();
322	}
323	
324	}  // namespace rime
