19	class SchemaSelection : public SimpleCandidate, public SwitcherCommand {
20	 public:
21	  SchemaSelection(Schema* schema)
22	      : SimpleCandidate("schema", 0, 0, schema->schema_name()),
23	        SwitcherCommand(schema->schema_id()) {}
24	  virtual void Apply(Switcher* switcher);
25	};
26	
27	void SchemaSelection::Apply(Switcher* switcher) {
28	  switcher->DeactivateAndApply([this, switcher] {
29	    if (Engine* engine = switcher->attached_engine()) {
30	      if (keyword_ != engine->schema()->schema_id()) {
31	        engine->ApplySchema(new Schema(keyword_));
32	      }
33	    }
34	  });
35	}
