171	void ConcreteEngine::CalculateSegmentation(Segmentation* segments) {
172	  DLOG(INFO) << "CalculateSegmentation, segments: " << segments->size()
173	             << ", finished? " << segments->HasFinishedSegmentation();
174	  while (!segments->HasFinishedSegmentation()) {
175	    size_t start_pos = segments->GetCurrentStartPosition();
176	    size_t end_pos = segments->GetCurrentEndPosition();
177	    DLOG(INFO) << "start pos: " << start_pos;
178	    DLOG(INFO) << "end pos: " << end_pos;
179	    // recognize a segment by calling the segmentors in turn
180	    for (auto& segmentor : segmentors_) {
181	      if (!segmentor->Proceed(segments))
182	        break;
183	    }
184	    DLOG(INFO) << "segmentation: " << *segments;
185	    // no advancement
186	    if (start_pos == segments->GetCurrentEndPosition())
187	      break;
188	    // only one segment is allowed past caret pos, which is the segment
189	    // immediately after the caret.
190	    if (start_pos >= context_->caret_pos())
191	      break;
192	    // move onto the next segment...
193	    if (!segments->HasFinishedSegmentation())
194	      segments->Forward();
195	  }
196	  // start an empty segment only at the end of a confirmed composition.
197	  if (!segments->empty() && !segments->back().HasTag("placeholder"))
198	    segments->Trim();
199	  if (!segments->empty() && segments->back().status >= Segment::kSelected)
200	    segments->Forward();
201	}
