284	void ConcreteEngine::ApplySchema(Schema* schema) {
285	  if (!schema)
286	    return;
287	  schema_.reset(schema);
288	  context_->Clear();
289	  context_->ClearTransientOptions();
290	  InitializeComponents();
291	  InitializeOptions();
292	  switcher_->SetActiveSchema(schema_->schema_id());
293	  message_sink_("schema", schema_->schema_id() + "/" + schema_->schema_name());
294	}
